SELECT type_name
FROM instruction_types
WHERE category = 'Control Flow';

SELECT name
FROM instructions
WHERE overflow = 1;

SELECT microcontroller_name
FROM microcontrollers
ORDER BY microcontroller_name ASC;

SELECT board_name, description
FROM development_boards
ORDER BY board_name ASC;

SELECT AVG(instruction_count) AS average_instructions_per_microcontroller
FROM (
  SELECT microcontroller_id, COUNT(instruction_id) AS instruction_count
  FROM instructions
  GROUP BY microcontroller_id
) AS subquery;
